const cfg = $('Set Config').first().json;

const safeGet = (n) => {
  try {
    const j = $(n).first().json;
    if (j?.error || j?.statusCode >= 400) return null;
    return j;
  } catch { return null; }
};

const safeGetAll = (n) => {
  try {
    return $(n).all()
      .map(i => i.json)
      .filter(j => j && !j.error && !(j.statusCode >= 400));
  } catch { return []; }
};

const fmtSeconds = (s) => {
  if (!s || isNaN(s)) return 'N/A';
  s = Math.round(s);
  if (s < 60) return s + 's';
  if (s < 3600) return Math.floor(s/60) + 'm ' + (s%60) + 's';
  return Math.floor(s/3600) + 'h ' + Math.floor((s%3600)/60) + 'm';
};

const dedupeById    = (arr) => { const seen = new Set(); return arr.filter(x => { if (!x?.id || seen.has(x.id)) return false; seen.add(x.id); return true; }); };
const dedupeByTitle = (arr) => { const seen = new Set(); return arr.filter(x => { if (!x?.title || seen.has(x.title)) return false; seen.add(x.title); return true; }); };
const dedupeByTs    = (arr) => { const seen = new Set(); return arr.filter(x => { const k = x?.timestamp ?? x?.date; if (seen.has(k)) return false; seen.add(k); return true; }); };

const summary    = safeGet('Fetch Account Summary');
const convVolume = dedupeByTs(safeGetAll('Fetch Conv Volume'));
const resTrend   = dedupeByTs(safeGetAll('Fetch Resolution Trend'));
const rawAgents  = dedupeById(safeGetAll('Fetch Agents List'));
const rawTeams   = dedupeById(safeGetAll('Fetch Teams List'));
const _labelsRaw = safeGet('Fetch Labels List'); const rawLabels  = dedupeByTitle(Array.isArray(_labelsRaw?.payload) ? _labelsRaw.payload : safeGetAll('Fetch Labels List'));
const _inboxesRaw = safeGet('Fetch Inboxes List'); const rawInboxes = dedupeById(Array.isArray(_inboxesRaw?.payload) ? _inboxesRaw.payload : safeGetAll('Fetch Inboxes List'));
// CSAT — handles both /metrics aggregate format and legacy individual-row format
const csatRaw  = safeGet('Fetch CSAT Reports');
const csatRows = Array.isArray(csatRaw?.data) ? csatRaw.data : [];
// /metrics endpoint returns { total_count, ratings: { Satisfied, Neutral, Dissatisfied } }
const csatIsMetrics = csatRaw && csatRaw.total_count !== undefined;
const totalR   = csatIsMetrics ? (csatRaw.total_count ?? 0)   : csatRows.length;
const posCount = csatIsMetrics ? (csatRaw.ratings?.Satisfied ?? csatRaw.satisfaction_data?.Satisfied ?? 0) : csatRows.filter(r=>r.rating>=4).length;
const negCount = csatIsMetrics ? (csatRaw.ratings?.Dissatisfied ?? csatRaw.satisfaction_data?.Dissatisfied ?? 0) : csatRows.filter(r=>r.rating<=2).length;
const sumR     = csatIsMetrics ? 0 : csatRows.reduce((a,r) => a+(r.rating??0), 0);

// Overview responses — summary_reports/team|inbox return arrays; inbox_label_matrix handled separately
const agentOvRaw = safeGet('Fetch Agent Conv Overview');
const agentOv  = Array.isArray(agentOvRaw) ? agentOvRaw : (Array.isArray(agentOvRaw?.data) ? agentOvRaw.data : safeGetAll('Fetch Agent Conv Overview'));
const teamOvRaw  = safeGet('Fetch Team Conv Overview');
const teamOv   = Array.isArray(teamOvRaw)  ? teamOvRaw  : (Array.isArray(teamOvRaw?.data)  ? teamOvRaw.data  : safeGetAll('Fetch Team Conv Overview'));
const inboxOvRaw = safeGet('Fetch Inbox Conv Overview');
const inboxOv  = Array.isArray(inboxOvRaw) ? inboxOvRaw : (Array.isArray(inboxOvRaw?.data) ? inboxOvRaw.data : safeGetAll('Fetch Inbox Conv Overview'));
const labelOvRaw = safeGet('Fetch Label Conv Overview');
const labelOv  = Array.isArray(labelOvRaw) ? labelOvRaw : (Array.isArray(labelOvRaw?.data) ? labelOvRaw.data : safeGetAll('Fetch Label Conv Overview'));

const agentRows = rawAgents.map(agent => {
  const ov = agentOv.find(o=>o.id===agent.id)??{};
  const ar  = csatRows.filter(r=>r.assigned_agent?.id===agent.id);
  return {
    id: agent.id, name: agent.name, email: agent.email,
    availability: agent.availability_status,
    assigned: ov.conversations_count??0,
    resolved: ov.resolutions_count??0,
    resolutionRate: ov.conversations_count ? Math.round((ov.resolutions_count/ov.conversations_count)*100) : 0,
    avgFirstResponse:  fmtSeconds(ov.avg_first_response_time),
    avgResolutionTime: fmtSeconds(ov.avg_resolution_time),
    csatRating: ar.length ? (ar.reduce((a,r)=>a+r.rating,0)/ar.length).toFixed(1) : null
  };
});

const teamRows = rawTeams.map(team => {
  const ov = teamOv.find(o=>o.id===team.id)??{};
  return {
    id: team.id, name: team.name, agentCount: team.agents_count??0,
    conversations: ov.conversations_count??0, resolved: ov.resolutions_count??0,
    resolutionRate: ov.conversations_count ? Math.round((ov.resolutions_count/ov.conversations_count)*100) : 0,
    avgFirstResponse: fmtSeconds(ov.avg_first_response_time),
    avgResolutionTime: fmtSeconds(ov.avg_resolution_time)
  };
});

const inboxRows = (Array.isArray(rawInboxes)?rawInboxes:[]).map(inbox => {
  const ov = inboxOv.find(o=>o.id===inbox.id)??{};
  return {
    id: inbox.id, name: inbox.name, channelType: inbox.channel_type,
    conversations: ov.conversations_count??0, resolved: ov.resolutions_count??0,
    pending: ov.open_conversations_count??0,
    avgFirstResponse: fmtSeconds(ov.avg_first_response_time),
    avgResolutionTime: fmtSeconds(ov.avg_resolution_time)
  };
});

const labelRows = (Array.isArray(rawLabels)?rawLabels:[]).map(label => {
  const ov = labelOv.find(o=>o.id===label.id||o.title===label.title)??{};
  return {
    id: label.id, title: label.title, color: label.color,
    conversations: ov.conversations_count??0, resolved: ov.resolutions_count??0,
    avgResolutionTime: fmtSeconds(ov.avg_resolution_time)
  };
});

return [{ json: {
  meta: {
    generatedAt: new Date().toISOString(),
    period: { since: cfg.since, until: cfg.until, groupBy: cfg.groupBy }
  },
  summary: {
    totalConversations: summary?.conversations_count??0,
    resolved:           summary?.resolutions_count??0,
    incomingMessages:   summary?.incoming_messages_count??0,
    outgoingMessages:   summary?.outgoing_messages_count??0,
    avgFirstResponse:   fmtSeconds(summary?.avg_first_response_time),
    avgResolutionTime:  fmtSeconds(summary?.avg_resolution_time),
    replyTime:          fmtSeconds(summary?.reply_time)
  },
  charts: {
    conversationVolume: convVolume.map(p=>({ date: new Date(p.timestamp*1000).toLocaleDateString('en-US',{hour:'2-digit',hour12:false}), value: p.value })),
    resolutionTrend:    resTrend.map(p=>({ date: new Date(p.timestamp*1000).toLocaleDateString('en-US',{hour:'2-digit',hour12:false}), value: p.value }))
  },
  csat: {
    score: totalR>0?Math.round((posCount/totalR)*100):null,
    avgRating: (!csatIsMetrics && totalR>0) ? parseFloat((sumR/totalR).toFixed(1)) : null,
    totalResponses: totalR, positive: posCount, negative: negCount,
    neutral: csatIsMetrics ? (csatRaw.ratings?.Neutral ?? csatRaw.satisfaction_data?.Neutral ?? 0) : csatRows.filter(r=>r.rating===3).length,
    ratingDistribution: csatIsMetrics
      ? [
          { label: 'Satisfied',    count: csatRaw.ratings?.Satisfied    ?? 0, pct: totalR>0?Math.round((csatRaw.ratings?.Satisfied??0)/totalR*100):0 },
          { label: 'Neutral',      count: csatRaw.ratings?.Neutral      ?? 0, pct: totalR>0?Math.round((csatRaw.ratings?.Neutral??0)/totalR*100):0 },
          { label: 'Dissatisfied', count: csatRaw.ratings?.Dissatisfied ?? 0, pct: totalR>0?Math.round((csatRaw.ratings?.Dissatisfied??0)/totalR*100):0 }
        ]
      : [5,4,3,2,1].map(star=>({
          stars: star,
          count: csatRows.filter(r=>r.rating===star).length,
          pct: totalR>0?Math.round(csatRows.filter(r=>r.rating===star).length/totalR*100):0
        })),
    recentResponses: csatRows.slice(0,50).map(r=>({
      rating: r.rating, feedback: r.feedback_message,
      agent: r.assigned_agent?.name??'Unassigned',
      contact: r.contact?.name??'Unknown', createdAt: r.created_at
    }))
  },
  agents: agentRows, teams: teamRows, inboxes: inboxRows, labels: labelRows
}}];

const now = new Date();
const data = $input.first().json;
return [{ json: {
  ...data,
  _savedAt:     now.toISOString(),
  _nextRefresh: new Date(now.getTime() + 60 * 60 * 1000).toISOString()
}}];

const data = $input.first().json;

if (!data || !data._savedAt) {
  return [{ json: {
    _cacheStatus: 'missing',
    _cacheError:  'Google Drive file is empty. Run the collection workflow first (Run Manually trigger).'
  }}];
}

const ageMs      = Date.now() - new Date(data._savedAt).getTime();
const ageMinutes = Math.floor(ageMs / 60000);
const isStale    = ageMs > 2 * 60 * 60 * 1000;

return [{ json: {
  ...data,
  _cache: {
    status:      isStale ? 'stale' : 'fresh',
    cachedAt:    data._savedAt,
    nextRefresh: data._nextRefresh,
    ageMinutes
  }
}}];

const data = $input.first().json;

const esc = (s) => String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

if (!data || !data._savedAt) {
  const html = `<!DOCTYPE html><html><head><title>Chatwoot Reports – Cache Status</title><style>body{font-family:sans-serif;padding:40px;background:#1a1a2e;color:#eee}h1{color:#e74c3c}.empty{background:#2d2d44;padding:20px;border-radius:8px;border-left:4px solid #e74c3c}</style></head><body><h1>Cache Status</h1><div class="empty"><strong>Google Drive file is empty.</strong><br><br>The collection workflow has not run yet.<br><br><b>Fix:</b><ol><li>Make sure the workflow is <b>Active</b></li><li>Click the <b>"Run Manually"</b> trigger node → <b>Execute workflow</b></li><li>Wait ~30s, then reload this page</li></ol></div></body></html>`;
  return [{ json: { html } }];
}

const ageMs      = Date.now() - new Date(data._savedAt).getTime();
const ageMinutes = Math.floor(ageMs / 60000);
const isStale    = ageMs > 2 * 60 * 60 * 1000;
const statusColor = isStale ? '#e67e22' : '#2ecc71';
const statusLabel = isStale ? 'STALE' : 'FRESH';

const summary    = data.summary ?? {};
const agentCount = (data.agents ?? []).length;
const teamCount  = (data.teams ?? []).length;
const inboxCount = (data.inboxes ?? []).length;
const payloadSize = Math.round(JSON.stringify(data).length / 1024);
const nextRefresh = data._nextRefresh ? new Date(data._nextRefresh).toLocaleString() : 'unknown';

const html = `<!DOCTYPE html><html><head><title>Chatwoot Reports – Cache Status</title><style>body{font-family:sans-serif;padding:40px;background:#1a1a2e;color:#eee;max-width:800px;margin:0 auto}h1{color:#a29bfe}h2{color:#74b9ff;margin-top:32px}.card{background:#2d2d44;padding:20px;border-radius:8px;margin:16px 0}.badge{display:inline-block;padding:4px 12px;border-radius:20px;font-weight:bold;font-size:14px}.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.metric{background:#1e1e35;padding:16px;border-radius:6px;text-align:center}.metric .val{font-size:28px;font-weight:bold;color:#a29bfe}.metric .lbl{font-size:12px;color:#aaa;margin-top:4px}pre{background:#111;padding:16px;border-radius:6px;overflow:auto;max-height:400px;font-size:12px}a{color:#74b9ff}</style></head><body><h1>Chatwoot Reports – Cache Status</h1><div class="card"><p>Status: <span class="badge" style="background:${statusColor};color:#000">${statusLabel}</span></p><p><b>Saved at:</b> ${esc(data._savedAt)}</p><p><b>Age:</b> ${ageMinutes} minutes</p><p><b>Next refresh:</b> ${esc(nextRefresh)}</p><p><b>Payload size:</b> ${payloadSize} KB</p><p><b>Data endpoint:</b> <a href="/webhook/chatwoot-reports" target="_blank">/webhook/chatwoot-reports</a></p></div><h2>Summary Metrics</h2><div class="grid"><div class="metric"><div class="val">${esc(summary.totalConversations)}</div><div class="lbl">Conversations</div></div><div class="metric"><div class="val">${esc(summary.resolved)}</div><div class="lbl">Resolved</div></div><div class="metric"><div class="val">${esc(summary.avgResolutionTime)}</div><div class="lbl">Avg Resolution</div></div><div class="metric"><div class="val">${agentCount}</div><div class="lbl">Agents</div></div><div class="metric"><div class="val">${teamCount}</div><div class="lbl">Teams</div></div><div class="metric"><div class="val">${inboxCount}</div><div class="lbl">Inboxes</div></div></div><h2>Raw Payload</h2><pre>${esc(JSON.stringify(data, null, 2))}</pre></body></html>`;

return [{ json: { html } }];
